window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q13"]=window.__LIBQ["tien-nghich"]["q13"]||{};window.__LIBQ["tien-nghich"]["q13"]["artifacts"]={"updatedAt":"2026-07-13","count":40,"artifacts":[{"id":"vu-kiem-van-truong","name":"Vũ kiếm vạn trượng","cn":"雨剑","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cực phẩm (uy lực khiến cao thủ Không Linh do dự)","soHuu":["Vương Lâm","Tạ Thanh"],"trangThai":"dang-co","blurb":"Thanh kiếm khổng lồ cao vạn trượng do Vương Lâm ngưng tụ từ nước mưa gần nửa Thanh Linh Tinh, cắm trên đỉnh Hoành Vân Sơn để trấn hộ tinh cầu. Bên trong chứa hai đạo bổn nguyên đại thành (Cổ Thần lực và lôi hỏa) cùng khí thế Đạo Cổ, kiếm ý lan tỏa tinh không khiến ngay cả cao thủ Không Linh cũng phải do dự.","detail":"Vương Lâm vung một trảo vào hư vô, thu toàn bộ nước mưa gần nửa Thanh Linh Tinh ngưng tụ thành thanh vũ kiếm cao ước chừng vạn trượng, cắm xuống đỉnh Hoành Vân Sơn, phần lộ ra cao sáu bảy ngàn trượng @c1389. Thanh kiếm chứa Cổ Thần lực thông qua tinh điểm mi tâm cùng lôi hỏa bổn nguyên — cả hai đều đã đạt bổn nguyên đại thành — kết hợp khí thế Đạo Cổ. Kiếm ý từ vũ kiếm lan tỏa ra tinh không, mang uy áp cực lớn: nhóm tu sĩ Lôi Tiên Điện khi còn cách ba ngàn vạn dặm đã bị kiếm ý xông tới, phun máu tươi; ngay cả cao thủ cảnh giới Không Linh trước kiếm ý này cũng phải do dự không dám khinh tiến. Vương Lâm tuyên bố thanh kiếm sẽ là lễ nhập môn dành cho Tạ Thanh khi hắn hoàn toàn minh ngộ.","phanLoaiPhu":"Trấn tinh kiếm","hinhDang":"Thanh kiếm khổng lồ cao vạn trượng, ngưng tụ từ nước mưa","nguonGoc":"Vương Lâm ngưng tụ từ nước mưa Thanh Linh Tinh","uyLuc":"Kiếm ý lan tỏa tinh không, khiến cao thủ cảnh giới Không Linh phải do dự; nhóm tu sĩ Lôi Tiên Điện ở cách ba ngàn vạn dặm đã bị kiếm ý xông tới, phun máu tươi.","dacDiem":"Ngưng tụ từ nước mưa gần nửa Thanh Linh Tinh, cao vạn trượng, phần lộ trên đỉnh Hoành Vân Sơn khoảng sáu bảy ngàn trượng; nội hàm hai đạo bổn nguyên đại thành và khí thế Đạo Cổ.","chuHienThoi":"Cắm trên Hoành Vân Sơn, dự định ban cho Tạ Thanh","congNang":["Trấn hộ tinh cầu — kiếm ý tự động lan tỏa tinh không, xông tới kẻ xâm nhập @c1389","Chứa hai đạo bổn nguyên đại thành (Cổ Thần lực qua tinh điểm mi tâm và lôi hỏa) cùng khí thế Đạo Cổ @c1389"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1389","denChuong":"","cachCoDuoc":"Tự ngưng tụ từ nước mưa","trangThai":"dang-co"},{"ten":"Tạ Thanh","tuChuong":"","denChuong":"","cachCoDuoc":"Lễ nhập môn khi minh ngộ (chưa nhận)","trangThai":"chua-nhan"}],"tabs":{"tienTrinh":[{"chuong":"@c1389","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm ngưng tụ và cắm kiếm trấn hộ Thanh Linh Tinh","text":"Vương Lâm thu nước mưa gần nửa Thanh Linh Tinh ngưng tụ thành vũ kiếm vạn trượng cắm trên đỉnh Hoành Vân Sơn, chú nhập Cổ Thần lực và lôi hỏa bổn nguyên cùng khí thế Đạo Cổ.","phamCap":"Cực phẩm","anchor":"hóa thành một thanh vũ kiếm rất lớn cao ước chừng vạn trượng"}]},"capNhatToi":"@c1389","nguon":["@c1389"]},{"id":"chieu-lenh-phong-chan-tien","name":"Chiếu lệnh phong chân tiên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Gia tộc tu chân viễn cổ thần bí"],"trangThai":"dang-co","blurb":"Chiếu lệnh do gia tộc tu chân viễn cổ thần bí gửi ra cho cuộc đại chiến, có công năng phong chân tiên.","detail":"Gia tộc tu chân viễn cổ thần bí gửi ra một chiếu lệnh phong chân tiên, kèm theo phái đệ cửu trưởng lão (Khất Mộc Tử) cho cuộc đại chiến.","congNang":["Phong chân tiên"],"nguonGoc":"Gia tộc tu chân viễn cổ thần bí","chuSoHuu":[{"ten":"Gia tộc tu chân viễn cổ thần bí","tuChuong":"@c1390","denChuong":"","cachCoDuoc":"Sở hữu gốc","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1390","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ","text":"Được nhắc tới khi mô tả gia tộc viễn cổ thần bí chỉ gửi ra một chiếu lệnh và phái một người cho cuộc đại chiến.","anchor":"gia tộc thần bí cổ xưa này cũng chỉ gửi ra một chiếu lệnh, phát một người ra mà thôi"}]},"nguon":["@c1390"]},{"id":"huyet-kiem-tay-tu-phuong","name":"Huyết kiếm (bản mệnh pháp bảo Tây Tử Phượng)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Tây Tử Phượng"],"trangThai":"đang sử dụng","blurb":"Thanh trường kiếm đỏ như máu do Vương Lâm đích thân luyện chế giữa trời tuyết, ngưng tụ từ tinh thể băng tuyết, nhuốm máu Cổ Thần và dung nhập một tia Cực Cảnh Lôi đình. Kiếm bay vào cơ thể Tây Tử Phượng trở thành bản mệnh pháp bảo, sát khí ngợp trời, dưới bước thứ ba không ai chịu nổi một nhát kiếm.","detail":"Giữa trời tuyết, Vương Lâm ngưng tụ tuyết thành tinh thể băng, phun máu Cổ Thần nhuốm đỏ toàn bộ, rồi vỗ thành một thanh trường kiếm đỏ như máu. Tiếp đó, Vương Lâm rút một tia Cực Cảnh Lôi đình từ mắt phải nhập vào kiếm, đạt đến dung hợp hoàn mỹ. Thanh kiếm mang sát khí ngợp trời, được Vương Lâm tuyên bố rằng dưới bước thứ ba không ai có thể chịu nổi một nhát kiếm. Sau khi luyện thành, kiếm tự bay vào cơ thể Tây Tử Phượng, dung nhập trở thành bản mệnh pháp bảo của nàng.","hinhDang":"Trường kiếm đỏ như máu","vatLieu":"Tinh thể băng tuyết, máu Cổ Thần, Cực Cảnh Lôi đình","nguonGoc":"Do Vương Lâm luyện chế giữa trời tuyết","uyLuc":"Dưới bước thứ ba không ai chịu nổi một nhát kiếm.","chuHienThoi":"Tây Tử Phượng","congNang":["Sát khí ngợp trời, uy lực cực mạnh, dưới bước thứ ba không ai chịu nổi một nhát kiếm @c1399","Dung nhập cơ thể chủ nhân, trở thành bản mệnh pháp bảo @c1399"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1399","denChuong":"@c1399","cachCoDuoc":"Tự luyện chế","trangThai":"đã tặng"},{"ten":"Tây Tử Phượng","tuChuong":"@c1399","denChuong":"","cachCoDuoc":"Vương Lâm tặng","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c1399","loai":"xuất hiện","importance":"major","giaiDoan":"Luyện chế và trao tặng","text":"Vương Lâm ngưng tụ tuyết nhuốm máu Cổ Thần nhập Cực Cảnh Lôi đình thành trường kiếm đỏ máu, tuyên bố dưới bước ba không ai chịu nổi một chém. Kiếm dung nhập cơ thể Tây Tử Phượng thành bản mệnh pháp bảo.","phamCap":"Cực mạnh dưới Bộ Hư Không","anchor":"Dưới bước thứ ba. không người nào có thể chịu được một chém củanhát kiếm từ kiếm này!"}]},"capNhatToi":"@c1399","nguon":["@c1399"]},{"id":"la-thien-thu","name":"La Thiên Thụ","cn":"罗天树","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không Niết","soHuu":["Lôi Tiên Điện"],"trangThai":"moi-luyen","blurb":"La Thiên Thụ là pháp bảo cấp Không Niết do Lỗ Phu Tử đích thân luyện chế trong hiệp đấu văn luyện khí đầu tiên với Vương Lâm, trước mặt mấy vạn tu sĩ Lôi Tiên Điện. Lấy tinh quang La Thiên làm hồn phách, bụi đất vạn cổ làm thân, phong bổn nguyên và máu mấy vạn tu sĩ La Thiên làm huyết mạch, được tuyên bố là chí bảo của La Thiên Lôi Tiên Điện.","detail":"La Thiên Thụ được Lỗ Phu Tử luyện thành qua bốn bước trước sự chứng kiến của mấy vạn tu sĩ Lôi Tiên Điện trong hiệp đấu văn luyện khí. Bước đầu tiên, Lỗ Phu Tử dùng tinh quang La Thiên ngưng tụ hình dạng một cây đại thụ cao mấy vạn trượng. Bước thứ hai, bụi đất tràn ngập tinh không La Thiên từ vạn cổ được dung nhập làm thân, thực chất hóa đại thụ. Bước thứ ba, phong bổn nguyên của Lỗ Phu Tử được dung nhập, tạo nên khí tức Không Niết kinh thiên. Bước thứ tư, mỗi tu sĩ La Thiên hiến một giọt máu mi tâm, cùng với máu bước thứ ba của Lỗ Phu Tử, hình thành huyết mạch tương liên với mấy vạn tu sĩ. Sau khi hoàn thành, đại thụ mấy vạn trượng được tinh chế thu nhỏ còn mười trượng. La Thiên Thụ được tuyên bố là chí bảo La Thiên Lôi Tiên Điện, sẽ ban tặng cho người giết địch nhiều nhất trong La Thiên","phanLoaiPhu":"Chí bảo tông môn","hinhDang":"Hình cây đại thụ, cao mười trượng (tinh chế từ mấy vạn trượng)","vatLieu":"Tinh quang La Thiên, bụi đất vạn cổ tinh không La Thiên, phong bổn nguyên Lỗ Phu Tử, máu mấy vạn tu sĩ La Thiên","nguonGoc":"Lỗ Phu Tử đích thân luyện trong hiệp đấu văn luyện khí","uyLuc":"Khí tức Không Niết kinh thiên, mang huyết mạch tương liên với mấy vạn tu sĩ La Thiên, được xưng là chí bảo La Thiên Lôi Tiên Điện.","dacDiem":"Lấy tinh không làm đất nuôi dưỡng, lấy bụi đất vạn cổ làm phân bón, lấy tinh quang La Thiên làm hồn phách; hình dạng đại thụ, ban đầu cao mấy vạn trượng, sau tinh chế thu nhỏ còn mười trượng.","chuHienThoi":"Lôi Tiên Điện (chưa ban thưởng)","congNang":["Mang khí tức pháp bảo Không Niết kinh thiên, hình thành từ phong bổn nguyên của Lỗ Phu Tử @c1401","Huyết mạch tương liên với mấy vạn tu sĩ La Thiên, được tạo bằng máu mi tâm của mỗi tu sĩ @c1401"],"chuSoHuu":[{"ten":"Lỗ Phu Tử","tuChuong":"@c1401","denChuong":"","cachCoDuoc":"Tự luyện","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1401","loai":"xuất hiện","importance":"major","phamCap":"Không Niết","giaiDoan":"Lỗ Phu Tử luyện thành trong đấu văn","text":"Lỗ Phu Tử luyện khí trước mấy vạn tu sĩ Lôi Tiên Điện, dùng tinh quang La Thiên, bụi đất vạn cổ, phong bổn nguyên và máu tu sĩ La Thiên tạo ra pháp bảo cấp Không Niết hình cây đại thụ, đặt tên La Thiên Thụ, tuyên bố là chí bảo Lôi Tiên Điện ban cho người đứng đầu La Thiên Tiên Bảng trong cuộc chiến giới ngoại.","anchor":"Pháp bảo này được đặt tên là La Thiên Thụ, đạo hữu thấy thế nào"}]},"capNhatToi":"@c1401","nguon":["@c1401"]},{"id":"huyet-tinh-vuong-lam","name":"Huyết tinh (sát khí cả đời Vương Lâm)","cn":"血晶","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (luyện từ chín tu chân tinh + sát khí cả đời)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Huyết tinh là pháp bảo ngưng tụ từ chín giọt tinh chất tu chân tinh, dung nhập toàn bộ sát khí cả đời Vương Lâm qua chín giai đoạn chiến sát, chứa vô số vong hồn. Viên huyết tinh không có bổn nguyên, không huyết mạch, không chiến ý — chỉ có thuần sát khí, uy lực đủ bức lui mấy vạn tu sĩ và khiến La Thiên Thụ suýt vỡ.","detail":"Vương Lâm dùng thể xác phá vỡ chín viên tu chân tinh, rút ra chín giọt chất lỏng màu vàng. Sau đó lần lượt dung nhập sát khí từ chín giai đoạn chiến sát trong đời: giết chóc trên Chu Tước Tinh, vong hồn Liên Minh Tinh Vực, giết chóc La Thiên Tinh Vực, sương máu Vân Hải Tinh Vực, đạo quả sát khí Thất Thải Giới, chém giết Thái Cổ Tinh Thần giới ngoại, diệt tộc Thiểm Lôi Tộc, mùi máu tanh cổ mộ, phá hủy Đông Lâm Tinh. Chín giọt tinh chất chuyển thành màu đỏ tươi rồi ngưng tụ thành một viên huyết tinh duy nhất, ẩn chứa vô số vong hồn. Đây là pháp bảo thuần túy sát khí, không mang bổn nguyên, không có huyết mạch, cũng không chứa chiến ý, chỉ là kết tinh của toàn bộ sát nghiệp một đời Vương Lâm.","congNang":["Ngưng tụ sát khí cả đời thành pháp bảo công kích @c1402","Ẩn chứa vô số vong hồn từ chín giai đoạn chiến sát @c1402"],"dacDiem":"Không bổn nguyên, không huyết mạch, không chiến ý — thuần sát khí cả đời, ngưng tụ từ chín giọt tinh chất tu chân tinh biến đỏ tươi.","uyLuc":"Bức lui mấy vạn tu sĩ phun máu, khiến Huyết Thần Tử phun máu, La Thiên Thụ mười trượng chấn động suýt vỡ, tinh trận dừng vận chuyển.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1402","denChuong":"","cachCoDuoc":"Tự luyện từ chín tu chân tinh + sát khí cả đời","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1402","loai":"xuất hiện","importance":"major","giaiDoan":"Luyện thành trong văn đấu với Lỗ Phu Tử","text":"Vương Lâm phá chín tu chân tinh rút tinh chất, dung nhập sát khí cả đời qua chín giai đoạn chiến sát, ngưng tụ thành viên huyết tinh chứa vô số vong hồn. Phóng tới Lỗ Phu Tử, bức lui mấy vạn tu sĩ phun máu, La Thiên Thụ chấn động suýt vỡ.","anchor":"Viên huyết tinh này ẩn chứa sự giết chóc cả đời của Vương Lâm"}]},"nguon":["@c1402"]},{"id":"muoi-tam-phap-bao-lo-phu-tu","name":"Mười tám pháp bảo của Lỗ Phu Tử","cn":null,"aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lỗ Phu Tử"],"trangThai":"Đang sử dụng","blurb":"Mười tám pháp bảo Lỗ Phu Tử luyện chế suốt mấy vạn năm, gồm trường thương gần ngàn trượng, đồ đao đen kịt, chín hạt châu cùng các món khác, đồng loạt xuất hiện trong cơn lốc tinh trận.","detail":"Lỗ Phu Tử tự bạch thiên tư kỳ dị, do hạn chế hương hỏa mà đình trệ ở Không Niết sơ kỳ, nhưng mấy vạn năm qua đã dồn tâm huyết luyện chế rất nhiều pháp bảo. Khi kích hoạt tinh trận La Thiên Tinh Vực, cơn lốc xoáy khổng lồ quét ngang tinh không, mười tám pháp bảo đồng loạt hiện ra: một cây trường thương gần ngàn trượng, một đồ đao đen kịt, chín hạt châu, và các pháp bảo khác — mỗi món đều bộc phát lực lượng kinh người, ngưng tụ thành sức ép khổng lồ bức thẳng tới Vương Lâm. Tuy nhiên, khi Chu Cẩn xuất hiện, ba tu sĩ bước thứ ba cùng tỏa uy áp, mười tám pháp bảo cùng tinh trận cũng không đủ sức đối kháng.","nguon":["@c1404"]},{"id":"phong-tien-gioi","name":"Phong Tiên Giới","cn":"封仙界","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão tổ Hướng gia"],"trangThai":"Đã phá hủy","blurb":"Biến ảo do lão tổ Hướng gia phóng ra từ tinh trận, hiện vô tận hư ảnh tiên nhân hình thành khí thế ngân hà, nhưng bị uy áp Linh Động Thượng Nhân và Chu Cẩn quét sạch, sụp đổ hoàn toàn.","detail":"Phong Tiên Giới là biến ảo / trận pháp phụ được lão tổ Hướng gia thi triển thông qua tinh trận La Thiên Tinh Vực, phóng ra vô tận hư ảnh tiên nhân tạo thành khí thế như ngân hà bức tới Vương Lâm. Tuy nhiên, khi Linh Động Thượng Nhân và Chu Cẩn đồng thời bước nửa bước về phía trước tỏa uy áp, Phong Tiên Giới lập tức chia năm xẻ bảy, nhanh chóng tiêu tan hoàn toàn.","nguon":["@c1404"]},{"id":"thanh-tan-kiem-huong-gia","name":"Tàn kiếm (Hướng gia)","cn":null,"aliases":["Thanh kiếm gãy"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão tổ Hướng gia","Lỗ Phu Tử"],"trangThai":"Bị thương / nứt nẻ","blurb":"Thanh tàn kiếm có kiếm linh, bức sát mi tâm Vương Lâm chưa tới mười trượng nhưng bị lực lượng ba tu sĩ bước thứ ba đè ép, bề mặt nứt nẻ, kiếm linh kêu thảm thiết phải lui về.","detail":"Thanh tàn kiếm từ phía Hướng gia, có kiếm linh bên trong. Trong trận đối đầu, tàn kiếm bức tới mi tâm Vương Lâm chỉ cách chưa tới mười trượng, nhưng bị lực lượng đồng thời của ba tu sĩ bước thứ ba (Vương Lâm, Linh Động Thượng Nhân, Chu Cẩn) đè ép. Bề mặt kiếm trong nháy mắt xuất hiện những vết nứt lan nhanh, kiếm linh phát ra tiếng kêu thảm thiết như bị thương nặng, phải run rẩy lui về bên cạnh Lỗ Phu Tử. Được so sánh rằng tàn kiếm có thể xuyên qua thân thể Thác Sâm nhưng không có tư cách đối mặt đồng thời ba tu sĩ bước thứ ba.","nguon":["@c1404"]},{"id":"yeu-dao-tang-tho","name":"Yêu đao Táng Thổ","cn":"妖刀葬土","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Vương tộc pháp khí","soHuu":["Vương Lâm"],"trangThai":"đổi chủ","blurb":"Yêu đao Táng Thổ là vương tộc pháp khí của Cổ Yêu lục tinh, một liêm đao màu tím chứa tinh điểm Cổ Yêu. Tại @c1406, Cổ Yêu liều mạng thi triển đao này chống Vương Lâm nhưng bị Vương Lâm một chưởng đoạt lấy, đao đổi chủ.","detail":"Yêu đao Táng Thổ là vương tộc pháp khí thuộc về Cổ Yêu lục tinh, mang hình dáng liêm đao màu tím. Trên thân đao tồn tại tinh điểm Cổ Yêu, chứng tỏ lai lịch bất phàm của pháp khí này. Khi khai đao, yêu khí gào thét cuồn cuộn, thể hiện uy thế hung mãnh của bảo vật cấp vương tộc. Trong trận chiến tại @c1406, Cổ Yêu lục tinh liều mạng thi triển Táng Thổ để chống lại Vương Lâm, nhưng Vương Lâm chỉ dùng một chưởng đã chụp lấy đao, khiến đao không thể thoát khỏi, bị thu đoạt và đổi chủ.","phanLoaiPhu":"liêm đao","hinhDang":"Liêm đao màu tím","vatLieu":"","nguonGoc":"Vương tộc pháp khí Cổ Yêu","uyLuc":"Khi thi triển, yêu khí gào thét cuồn cuộn, mang uy thế vương tộc pháp khí của Cổ Yêu, tuy nhiên vẫn bị Vương Lâm một chưởng chụp lấy không thể thoát.","dacDiem":"Liêm đao màu tím, trên thân đao tồn tại tinh điểm Cổ Yêu, khai đao thì yêu khí gào thét.","chuHienThoi":"Vương Lâm","congNang":["Liêm đao chiến đấu cấp vương tộc pháp khí, dùng trong cận chiến @c1406","Chứa tinh điểm Cổ Yêu, khi khai đao yêu khí gào thét @c1406"],"chuSoHuu":[{"ten":"Cổ Yêu","tuChuong":"@c1406","denChuong":"@c1406","cachCoDuoc":"Bản gốc sở hữu","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1406","denChuong":"","cachCoDuoc":"Đoạt từ Cổ Yêu bằng một chưởng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1406","loai":"đổi chủ","importance":"major","giaiDoan":"Cổ Yêu thi triển, bị Vương Lâm đoạt","text":"Cổ Yêu lục tinh liều mạng thi triển vương tộc pháp khí yêu đao Táng Thổ chống Vương Lâm. Vương Lâm một chưởng chụp lấy, đao không thể thoát, bị thu vào tay.","anchor":"Vương tộc pháp khí, yêu đao, Táng Thổ!","phamCap":"Vương tộc pháp khí"}]},"capNhatToi":"@c1406","nguon":["@c1406"]},{"id":"chat-thai-u-minh-thu","name":"Chất thải U Minh Thú","cn":null,"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":null,"soHuu":[],"trangThai":"Đã sử dụng làm dẫn đường","blurb":"Đống đá vụn trăm trượng — tàn tích tu chân tinh bị U Minh Thú nuốt rồi bài tiết, chứa linh khí nồng đậm nhưng đã chết.","detail":"Đống đá vụn nhiều màu sắc cao trăm trượng, thực chất là tàn tích của tu chân tinh hoang dã bị U Minh Thú nuốt vào thế giới bên trong cơ thể, trải qua thời gian lưu chuyển vạn năm hóa thành cát bụi rồi bị bài tiết ra ngoài. Linh khí bên trong nồng đậm hơn cả thượng phẩm linh thạch nhưng đã mất sức sống, mang dấu vết thời gian vạn năm và khí tức lờ mờ của U Minh Thú. Vương Lâm phát hiện đống đá này sau khi lục soát gần tám phần cấm địa sương mù, dùng khí tức U Minh Thú còn sót trong linh khí làm dẫn đường truy tìm con thú đang ngủ say.","nguon":["@c1410"]},{"id":"tam-bia-da-dao-kinh","name":"Tấm bia đá Đạo Kinh","cn":"道经碑","category":"khac","categoryLabel":"Khác","phamCap":null,"soHuu":[],"trangThai":"Xuất hiện từ hồn khẩu U Minh Thú","blurb":"Tấm bia đá rất lớn khắc chữ đỏ như máu — Đạo Kinh — xuất hiện từ hồn khẩu U Minh Thú khi thất thải bùng lên.","detail":"Tấm bia đá kích thước rất lớn, xuất hiện từ bên trong hồn khẩu U Minh Thú trong tiếng nổ ầm ầm khi ánh sáng thất thải bùng lên phá hủy hơn nửa phong ấn bên ngoài. Trên bia khắc những chữ rõ ràng đỏ như máu: Đạo Kinh. Nguồn gốc liên quan tới phần Thất Thải Giới đã bị U Minh Thú nuốt vào thế giới bên trong cơ thể hàng trăm năm trước. Xuất hiện cùng lúc với vô số thân ảnh Minh Chí Giả tràn ngập bát phương.","nguon":["@c1410"]},{"id":"dao-qua-mau-cam","name":"Đạo Quả màu cam","cn":"","aliases":[],"category":"khac","categoryLabel":"Đạo Quả","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đạo Quả màu cam lớn chừng mười trượng mang đạo niệm hỗn tạp, bị U Minh Thú vô tình hấp thụ khi nuốt Thất Thải Giới. Vương Lâm thu lấy, nhận định nó có thể giúp ba đạo bổn nguyên viên mãn.","detail":"Đạo Quả màu cam có kích thước khoảng mười trượng, chứa đạo niệm hỗn tạp. U Minh Thú khi nuốt Thất Thải Giới đã dùng quá nhiều sức, phá vỡ một vách ngăn nào đó và vô tình hấp thụ phải Đạo Quả này. Vương Lâm phát hiện sự bất thường, ra lệnh U Minh Thú nhả ra và thu lấy, nhận định nó có khả năng giúp ba đạo bổn nguyên — nhân quả, sinh tử, chân giả — đại thành viên mãn.","hinhDang":"Quả màu cam, lớn chừng mười trượng","nguonGoc":"Bị U Minh Thú vô tình hấp thụ khi nuốt Thất Thải Giới, phá vỡ vách ngăn nào đó","congNang":["Chứa đạo niệm hỗn tạp, có khả năng giúp ý cảnh ba đạo bổn nguyên — nhân quả, sinh tử, chân giả — đại thành viên mãn @c1412"],"chuSoHuu":[{"ten":"U Minh Thú","tuChuong":"@c1412","denChuong":"@c1412","cachCoDuoc":"Vô tình hấp thụ khi nuốt Thất Thải Giới","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1412","denChuong":"","cachCoDuoc":"Ra lệnh U Minh Thú nhả ra và thu lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1412","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và đổi chủ","text":"Vương Lâm phát hiện U Minh Thú đã hấp thụ một Đạo Quả khi nuốt Thất Thải Giới. Ra lệnh nhả ra, thu lấy Đạo Quả màu cam mười trượng mang đạo niệm hỗn tạp.","anchor":"chẳng lẽ nó đã hút vào một Đạo Quả"}]},"nguon":["@c1412"]},{"id":"huyet-cac-te-dan-phong-diet-toc","name":"Huyết các (tế đàn Phong Diệt Tộc)","cn":"血阁","category":"phap-bao","categoryLabel":"Pháp bảo / Tế đàn","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Tòa lầu các đỏ như máu, một trong ba phần tế đàn Phong Diệt Tộc. Được Cổ Yêu giao cho Vương Lâm, có thể dùng cảm ngộ Tam Mệnh Thuật.","detail":"Tế đàn Phong Diệt Tộc gồm ba tòa huyết các. Tòa này ẩn trong khe không gian mười trượng bên trong huyết tinh (tu chân tinh đỏ như máu) ở La Thiên Tinh Vực, được bảo vệ bởi tia máu chứa huyết mạch Diêu gia. Cổ Yêu lấy ra giao nộp cho Vương Lâm sau khi bị đấu trí. Vương Lâm nhận xét bản thân cũng đã có một tòa, nay sở hữu hai phần ba tế đàn. Có thể dùng để cảm ngộ Tam Mệnh Thuật — thành công sẽ sở hữu ba tính mạng.","nguonGoc":"Viễn Cổ Tiên Giới, ẩn trong huyết tinh La Thiên Tinh Vực","congNang":["Cảm ngộ Tam Mệnh Thuật trên tế đàn, thành công sở hữu ba tính mạng"],"laBo":true,"thanhVien":[{"id":"huyet-cac-te-dan-phong-diet-toc","vaiTro":"Tòa thứ nhất (thu từ Cổ Yêu)"},{"id":"huyet-cac","vaiTro":"Tòa thứ hai (Vương Lâm đã có từ trước)"}],"chuSoHuu":[{"ten":"Cổ Yêu","tuChuong":"@c1413","denChuong":"@c1413","cachCoDuoc":"Cất giữ trong khe không gian huyết tinh","trangThai":"da-giao"},{"ten":"Vương Lâm","tuChuong":"@c1413","denChuong":"","cachCoDuoc":"Ép Cổ Yêu giao nộp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1413","loai":"đổi chủ","importance":"major","giaiDoan":"Cổ Yêu giao nộp cho Vương Lâm","text":"Cổ Yêu bị Vương Lâm đấu trí, không dám đánh cuộc, tự lấy tòa huyết các đỏ như máu từ khe không gian trong huyết tinh giao cho Vương Lâm. Vương Lâm nay sở hữu hai trong ba tòa huyết các tế đàn Phong Diệt Tộc.","anchor":"một tòa lầu các đỏ như máu nhanh chóng bay ra, từ bên trong cái khe lóe lên"}]},"nguon":["@c1413"]},{"id":"manh-mai-rua","name":"Mảnh mai rùa","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"Không rõ","soHuu":["Thủy Đạo Tử"],"trangThai":"dang-co","blurb":"Tín vật thân phận đồng tử chủ nhân phong giới, tràn ngập khí tức tang thương và tiên khí tinh thuần cực điểm.","detail":"Mảnh mai rùa là tín vật xác nhận thân phận đồng tử của chủ nhân phong giới. Thủy Đạo Tử dùng nó liên lạc viễn cổ thượng tiên để xin ban bảo vật. Viễn cổ thượng tiên xác nhận mai rùa là thật trước khi ban chiếc chuông vàng.","congNang":["Xác nhận thân phận đồng tử chủ nhân phong giới","Liên lạc viễn cổ tiên vực xin bảo vật"],"chuSoHuu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1414","denChuong":"","cachCoDuoc":"Sở hữu sẵn với tư cách đồng tử","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1414","loai":"dùng","importance":"normal","giaiDoan":"Dùng liên lạc viễn cổ tiên vực","text":"Thủy Đạo Tử lấy ra mảnh mai rùa dùng liên lạc viễn cổ thượng tiên, xác nhận thân phận đồng tử chủ nhân phong giới, xin ban bảo vật.","anchor":"Mảnh mai rùa này tràn ngập một khí tức tang thương, mơ hồ còn có tiên khí tinh thuần cực điểm tràn ra"}]},"nguon":["@c1414"]},{"id":"lenh-bai-nuoc-mua-thanh-lam","name":"Lệnh bài nước mưa (Thanh Lâm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thanh Lâm"],"trangThai":"dang-co","blurb":"Lệnh bài tạo từ nước mưa Vũ tiên giới bằng thần lực Thanh Lâm, dùng truyền thần niệm bảo vệ Vương Lâm khuếch tán khắp liên minh và bốn phương.","detail":"Thanh Lâm dùng thần lực ngưng tụ nước mưa cả Vũ giới thành lệnh bài, cả Vũ giới chấn động khi ngưng tụ. Truyền vào thần niệm khẳng định Vương Lâm là đệ tử bổn tiên đế, khuếch tán vô tận.","congNang":["Truyền thần niệm khuếch tán vô tận khắp liên minh và bốn phương"],"chuSoHuu":[{"ten":"Thanh Lâm","tuChuong":"@c1415","denChuong":"","cachCoDuoc":"Tự tạo từ nước mưa Vũ giới","trangThai":"dang-co"}],"capNhatToi":"@c1415","tabs":{"tienTrinh":[{"chuong":"@c1415","loai":"xuat-hien","importance":"normal","giaiDoan":"Tạo và sử dụng","text":"Thanh Lâm dùng thần lực ngưng tụ nước mưa cả Vũ giới thành lệnh bài, truyền thần niệm bảo vệ Vương Lâm.","anchor":"cuối cùng xuyên thấu vào trong, ngưng tụ trên tay hắn thành một tấm lệnh bài tạo thành từ nước mưa"}]},"nguon":["@c1415"]},{"id":"dan-duoc-thuy-dao-tu-tang-moc-bang-mi","name":"Đan dược Thủy Đạo Tử tặng Mộc Băng Mi","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Mộc Băng Mi"],"trangThai":"dang-co","blurb":"Viên đan Thủy Đạo Tử tặng Mộc Băng Mi mấy trăm năm trước, hứa giúp khôi phục tu vi nhưng phải trả giá đắt.","detail":"Viên đan do Thủy Đạo Tử tặng, nói sẽ giúp khôi phục tu vi nhưng phải trả giá đắt, thời điểm thích hợp mới nên nuốt. Mộc Băng Mi run rẩy cầm đan, do dự. Có thể là bẫy.","congNang":["Khôi phục tu vi nhưng phải trả giá đắt"],"chuSoHuu":[{"ten":"Mộc Băng Mi","tuChuong":"@c1415","denChuong":"","cachCoDuoc":"Thủy Đạo Tử tặng mấy trăm năm trước","trangThai":"dang-co"}],"capNhatToi":"@c1415","tabs":{"tienTrinh":[{"chuong":"@c1415","loai":"xuat-hien","importance":"normal","giaiDoan":"Mộc Băng Mi lấy ra do dự","text":"Mộc Băng Mi lấy ra viên đan dược Thủy Đạo Tử tặng mấy trăm năm trước, run rẩy cầm đan, do dự nuốt hay không.","anchor":"Thủy Đạo Tử tặng nàng, từng có nói là sẽ giúp nàng khôi phục tu vi nhưng phải trả giá đắt"}]},"nguon":["@c1415"]},{"id":"ngon-nui-phap-bao-than-tong","name":"Ngọn núi pháp bảo Thần Tông","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật Thần Tông","soHuu":["Thủy Đạo Tử"],"trangThai":"hong","blurb":"Pháp bảo dạng ngọn núi khổng lồ có vô số cấm chế, bảo vật của Thần Tông do Thủy Đạo Tử sử dụng. Bị huyết kiếm Vương Lâm đâm xuyên phá nát hoàn toàn.","detail":"Ngọn núi khổng lồ chứa vô số cấm chế, được Thủy Đạo Tử dùng để đè nát tu sĩ Quy Nguyên Tông trong bồn địa. Bị huyết kiếm đâm xuyên, vết nứt đỏ máu tràn ngập khắp ngọn núi, sụp đổ hoàn toàn.","congNang":["Đè ép tiêu diệt diện rộng"],"chuSoHuu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1417","denChuong":"","cachCoDuoc":"","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1417","loai":"dùng","importance":"normal","giaiDoan":"Bị huyết kiếm phá hủy","text":"Thủy Đạo Tử dùng ngọn núi đè tu sĩ Quy Nguyên Tông. Huyết kiếm Vương Lâm đâm xuyên phá nát hoàn toàn.","anchor":"Ngọn núi này mặc dù là pháp bảo của Thủy Đạo Tử, mặc dù là bảo vật của Thần Tông"}]},"nguon":["@c1417"]},{"id":"ba-muoi-hai-hat-chau-ban-tinh","name":"Ba mươi hai hạt châu bàn tính","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vân Phong Tử"],"trangThai":"hong","blurb":"Pháp bảo của Vân Phong Tử, ba mươi hai hạt châu xếp thành hàng thẳng tắp, ẩn trong gợn sóng hình tròn để tấn công lén. Bị Chu Cẩn phá vỡ hoàn toàn.","detail":"Ba mươi hai hạt châu của một bàn tính xếp thành hàng thẳng tắp, ẩn trong gợn sóng hình tròn xuất hiện phía sau Vương Lâm tấn công lén. Bị Chu Cẩn thi triển Quần Lang Bái Nguyệt phá vỡ hoàn toàn, lộ ra bản thể nam tử trung niên đầy máu.","congNang":["Tấn công lén, ẩn trong gợn sóng hình tròn"],"chuSoHuu":[{"ten":"Vân Phong Tử","tuChuong":"@c1417","denChuong":"","cachCoDuoc":"","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1417","loai":"dùng","importance":"normal","giaiDoan":"Bị Chu Cẩn phá vỡ","text":"Vân Phong Tử dùng ba mươi hai hạt châu bàn tính tấn công sau lưng Vương Lâm, bị Chu Cẩn phá vỡ hoàn toàn.","anchor":"ba mươi hai hạt châu của một bàn tính tạo thành một hàng thẳng tắp đột nhiên lao tới"}]},"nguon":["@c1417"]},{"id":"truong-thuong-am-duong-mon-do","name":"Trường thương Âm Dương Môn Đồ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thủy Đạo Tử"],"trangThai":"khong-ro","blurb":"Trường thương khổng lồ hóa từ vô số Âm Dương Môn Đồ, dung hợp toàn bộ tu vi và hương hỏa cả đời của Thủy Đạo Tử thành đòn quyết tử nhắm vào Vương Lâm. Uy lực kinh thiên khiến tu chân tinh rung chuyển, xuất hiện rất nhiều vết nứt dường như sắp hủy diệt.","detail":"Thủy Đạo Tử mở ra khe nứt lớn, triệu hồi vô số Âm Dương Môn Đồ bay ra từ bên trong, toàn bộ hội tụ hóa thành một cây trường thương khổng lồ. Trường thương này dung hợp toàn bộ tu vi cả đời cùng toàn bộ hương hỏa của Thủy Đạo Tử, bản chất là chiêu liều mạng quyết tử nhằm đâm thẳng vào Vương Lâm. Khi trường thương xuất hiện, uy lực kinh thiên động địa khiến trời long đất lở, tu chân tinh xuất hiện rất nhiều vết nứt, dường như sắp bị hủy diệt.","congNang":["Dung hợp toàn bộ tu vi và hương hỏa cả đời của chủ nhân thành một đòn quyết tử có uy lực cực đại @c1417"],"chuSoHuu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1417","denChuong":"","cachCoDuoc":"Hóa từ Âm Dương Môn Đồ","trangThai":"khong-ro"}],"tabs":{"tienTrinh":[{"chuong":"@c1417","loai":"xuất hiện","importance":"major","giaiDoan":"Chiêu liều mạng của Thủy Đạo Tử","text":"Thủy Đạo Tử triệu hồi vô số Âm Dương Môn Đồ hóa trường thương dung hợp tu vi và hương hỏa cả đời. Uy lực khiến tu chân tinh nứt vỡ sắp hủy diệt.","anchor":"Cây thương này dung hợp tu vi cả đời của Thủy Đạo Tử, dung hợp toàn bộ hương hỏa của hắn"}]},"nguon":["@c1417"],"uyLuc":"Uy lực kinh thiên khiến trời long đất lở, tu chân tinh xuất hiện rất nhiều vết nứt dường như sắp hủy diệt.","dacDiem":"Pháp bảo tạm thời, hóa hình từ vô số Âm Dương Môn Đồ hội tụ thành cây trường thương khổng lồ; bản chất là chiêu thức liều mạng quyết tử, đánh đổi toàn bộ tu vi và hương hỏa cả đời."},{"id":"chuong-vang-vien-co-tien-vuc","name":"Chiếc chuông vàng Viễn cổ Tiên Vực","cn":"","aliases":["Cái chuông nhỏ","Chuông màu vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Viễn cổ Tiên Vực bảo vật","soHuu":["Thủy Đạo Tử"],"trangThai":"da-huy","blurb":"Chiếc chuông màu vàng có nguồn gốc từ Viễn cổ Tiên Vực, chứa tiên khí tinh thuần cực điểm, chỉ chủ nhân mới điều khiển được. Bị Thủy Đạo Tử phun máu tươi kích nổ toàn bộ sức mạnh bên trong tạo cuồng phong hủy diệt tầm tinh vực, sau đó chuông đã bị hủy.","detail":"Chiếc chuông vàng đến từ Viễn cổ Tiên Vực, chỉ chủ nhân là Thủy Đạo Tử mới có thể điều khiển nhờ bí thuật do Chủ nhân Phong Giới truyền cho và mai rùa trên thân chuông. Công năng chính của chuông là dung nhập vào Phong Giới Đại Trận để kéo dài thời gian cho giới nội thêm mấy trăm năm. Tại trận chiến ở Vân Hải Tinh Vực, Thủy Đạo Tử phun máu tươi lên chuông kích nổ toàn bộ tiên khí bên trong, tạo cuồng phong màu vàng đủ sức hủy diệt toàn bộ Vân Hải Tinh Vực nhằm tấn công Vương Lâm và chôn vùi Vân Hải. Cuồng phong cuối cùng bị Vu Minh Thú nuốt trọn. Chuông đã bị hủy hoàn toàn sau khi kích nổ.","phanLoaiPhu":"Chuông","hinhDang":"Chuông nhỏ màu vàng, thân có mai rùa","nguonGoc":"Viễn cổ Tiên Vực","uyLuc":"Nổ tung tạo cuồng phong màu vàng đủ sức hủy diệt toàn bộ Vân Hải Tinh Vực","dacDiem":"Chứa tiên khí tinh thuần cực điểm, chỉ chủ nhân mới điều khiển được nhờ bí thuật và mai rùa trên thân chuông","chuHienThoi":"Không còn (đã hủy)","congNang":["Dung nhập Phong Giới Đại Trận, kéo dài thời gian giới nội thêm mấy trăm năm","Kích nổ toàn bộ tiên khí bên trong tạo cuồng phong màu vàng có sức hủy diệt tầm tinh vực @c1419"],"chuSoHuu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1419","denChuong":"@c1419","cachCoDuoc":"Được Chủ nhân Phong Giới truyền bí thuật điều khiển","trangThai":"da-huy"}],"capNhatToi":"@c1419","tabs":{"tienTrinh":[{"chuong":"@c1419","loai":"xuat-hien","importance":"major","giaiDoan":"Kích nổ và hủy","text":"Thủy Đạo Tử phun máu tươi lên chuông kích nổ toàn bộ sức mạnh tiên khí bên trong, tạo cuồng phong màu vàng đủ hủy diệt Vân Hải Tinh Vực. Cuồng phong bị Vu Minh Thú nuốt trọn, chuông bị hủy hoàn toàn.","anchor":"Chiếc chuông đến từ Viễn cổ Tiên Vực, có thể kéo dài thời gian cho giới nội thêm mấy trăm năm trong khoảnh khắc này nổ tung","phamCap":"Viễn cổ Tiên Vực bảo vật"}]},"nguon":["@c1419"]},{"id":"thai-co-tinh-than-bang","name":"Thái cổ Tinh Thần bảng","category":"khac","categoryLabel":"Bảng xếp hạng","soHuu":["Trưởng Tôn hội"],"trangThai":"dang-dung","blurb":"Bảng xếp hạng chiến công của giới ngoại Thái cổ Tinh Thần, được mở lại cho cuộc chiến xâm lược giới nội với phần thưởng hậu hĩnh.","detail":"Được Trưởng Tôn hội mở lại nhằm kích thích chiến ý cho cuộc xâm lược giới nội. Phần thưởng phân theo thứ hạng: một ngàn đứng đầu có cơ duyên viễn cổ tiên vực, một trăm đứng đầu làm đệ tử tiên phi, mười đứng đầu nắm quyền một giới, ba đứng đầu nếu bước thứ ba được mười phần đạo linh tam phẩm hoặc đệ tử chưởng tôn, người đứng đầu cuối cùng được song tu với tiên phi thành tiên tôn.","congNang":["Xếp hạng chiến công kèm phần thưởng kích thích chiến ý tu sĩ giới ngoại"],"tabs":{"tienTrinh":[{"chuong":"@c1422","loai":"xuat-hien","importance":"normal","giaiDoan":"Mở lại cho cuộc chiến xâm lược","text":"Trưởng Tôn hội mở lại Thái cổ Tinh Thần bảng, phân thưởng phân cấp từ cơ duyên viễn cổ tiên vực tới song tu với tiên phi.","anchor":"Mở lại Thái cổ Tinh Thần bảng, lưu danh muôn thủa"}]},"nguon":["@c1422"]},{"id":"tat-sat-bang","name":"Tất sát bảng","category":"khac","categoryLabel":"Bảng truy sát","soHuu":["Trưởng Tôn hội"],"trangThai":"dang-dung","blurb":"Bảng truy sát của giới ngoại, mở đồng thời với Thái cổ Tinh Thần bảng. Vương Lâm là mục tiêu, ai giết được coi như giết một vạn tu sĩ giới nội.","detail":"Bảng treo thưởng truy sát do giới ngoại mở ra, nhắm vào các mục tiêu quan trọng của giới nội. Vương Lâm tạm thời nằm trên bảng.","congNang":["Treo thưởng truy sát mục tiêu quan trọng giới nội"],"tabs":{"tienTrinh":[{"chuong":"@c1422","loai":"xuat-hien","importance":"normal","giaiDoan":"Mở ra cùng Thái cổ Tinh Thần bảng","text":"Mở đồng thời với Thái cổ Tinh Thần bảng, Vương Lâm là mục tiêu trên bảng.","anchor":"Sau khi Thái cổ Tinh Thần bảng mở ra, đồng thời mở ra Tất sát bảng của giới ngoại"}]},"nguon":["@c1422"]},{"id":"thanh-kiem-trong-suot","name":"Thanh kiếm trong suốt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiên Phạt Điện"],"trangThai":"dang-co","blurb":"Thanh kiếm dài bảy thước rộng tam tấc, toàn thân trong suốt, tràn ngập lực lượng hương hỏa, bên ngoài hiện cảnh tượng hư ảo thế giới hương hỏa với dân chúng điên cuồng hiến tế.","detail":"Từ lầu các đen Thiên Phạt Điện lóe ra, toàn thân trong suốt tỏa ánh sáng chói mắt. Chứa lực hương hỏa, tham gia phá Phong Giới Đại Trận.","congNang":["Chứa lực hương hỏa","Phá Phong Giới Đại Trận"],"hinhDang":"Dài bảy thước, rộng tam tấc, toàn thân trong suốt","chuSoHuu":[{"ten":"Thiên Phạt Điện","tuChuong":"@c1423","denChuong":"","cachCoDuoc":"Sở hữu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1423","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện phá Phong Giới Đại Trận","text":"Từ lầu các đen lóe ra, tràn ngập lực lượng hương hỏa, bên ngoài hiện cảnh hương hỏa giới với dân chúng hiến tế.","anchor":"Kiếm dài bảy thước, rộng chừng tam tấc, toàn thân trong suốt, tỏa ra ánh sáng chói mắt"}]},"nguon":["@c1423"]},{"id":"ngoc-nhu-y-chin-canh-hoa","name":"Ngọc như ý","cn":"","aliases":["Ngọc như ý (đóa hoa chín cánh)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nữ tử ung dung cao quý"],"trangThai":"dang-co","blurb":"Ngọc như ý trên có đóa hoa, nữ tử ung dung điểm vào khiến hoa sống lại, chín cánh nở xoay tròn thành cơn lốc lao lên tinh không tham gia phá Phong Giới Đại Trận.","detail":"Vốn trên ngọc như ý có một đóa hoa chết, bị nữ tử điểm vào dường như được ban cho tính mạng. Chín cánh hoa nở xoay tròn thành cơn lốc.","congNang":["Hồi sinh đóa hoa, tạo cơn lốc chín cánh hoa phá trận"],"tabs":{"tienTrinh":[{"chuong":"@c1423","loai":"dùng","importance":"normal","giaiDoan":"Tạo cơn lốc chín cánh hoa","text":"Nữ tử ung dung điểm vào đóa hoa trên ngọc như ý, hoa sống lại, chín cánh nở xoay tròn thành cơn lốc lao lên bầu trời.","anchor":"Trên ngọc như ý có một đóa hoa, vốn là vật chết nhưng giờ phút này bị nữ tử điểm vào dường như được ban cho tính mạng"}]},"nguon":["@c1423"]},{"id":"day-co-cam-lam-mong","name":"Dây cổ cầm đứt","cn":"","aliases":["Dây cổ cầm chứa tu vi Lam Mộng Đạo Tôn"],"category":"khac","categoryLabel":"Khác","phamCap":"Bước thứ ba (ước đoán)","soHuu":["Lam Mộng Đạo Tôn"],"trangThai":"da-dung","blurb":"Dây cổ cầm đứt là đoạn dây đàn bị đứt khi thoa vàng cắm xuống, được Lam Mộng Đạo Tôn dùng ánh sáng lam bao phủ, phun máu tươi dung nhập vào bên trong, chứa toàn bộ tu vi cả đời cùng hương hỏa lực, rồi phóng lên tinh không tham gia phá Phong Giới Đại Trận.","detail":"Đoạn dây đàn vốn bị đứt ra khi thoa vàng cắm xuống. Lam Mộng Đạo Tôn đã dùng ánh sáng lam bao phủ đoạn dây đàn này, đồng thời phun máu tươi dung nhập vào bên trong, gửi gắm tu vi cả đời của hắn cùng một lượng lớn hương hỏa lực. Sau đó, đoạn dây đàn được phóng lên bầu trời, hội tụ cùng thanh kiếm trong suốt và các sức mạnh khác nhằm hợp lực phá vỡ Phong Giới Đại Trận.","congNang":["Chứa toàn bộ tu vi cả đời và hương hỏa lực của Lam Mộng Đạo Tôn sau khi được dung nhập máu tươi @c1423","Được phóng lên tinh không, hội tụ cùng các sức mạnh khác để tham gia phá Phong Giới Đại Trận @c1423"],"chuSoHuu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1423","denChuong":"","cachCoDuoc":"Tự tạo từ dây đàn đứt","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1423","loai":"dùng","importance":"major","giaiDoan":"Hy sinh tu vi phá trận","text":"Lam Mộng Đạo Tôn dùng ánh sáng lam bao phủ đoạn dây đàn đứt, phun máu tươi dung nhập chứa tu vi cả đời và hương hỏa lực, phóng lên bầu trời phá Phong Giới Đại Trận.","anchor":"bên trong có dung nhập máu tươi của Lam Mộng Đạo Tôn, chứa tu vi cả đời của hắn"}]},"nguon":["@c1423"],"uyLuc":"Mang toàn bộ tu vi cả đời của Lam Mộng Đạo Tôn cùng hương hỏa lực, góp phần hợp lực phá Phong Giới Đại Trận.","dacDiem":"Đoạn dây đàn đứt được bao phủ bởi ánh sáng lam và dung nhập máu tươi của Lam Mộng Đạo Tôn, trở thành vật chứa tu vi và hương hỏa lực."},{"id":"day-dan-lam-mong","name":"Dây đàn của Lam Mộng Đạo Tôn","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Lam Mộng Đạo Tôn"],"trangThai":"bi-huy (nổ tung phá trận)","blurb":"Pháp bảo của Lam Mộng Đạo Tôn, một trong năm pháp bảo phối hợp phá Phong Giới Đại Trận. Khi đối đầu trận linh, dây đàn va chạm kịch liệt với cây roi tử ý ngưng tụ, sau đó nổ tung theo lệnh để xé rộng khe hở trên trận pháp.","detail":"Dây đàn là pháp bảo do Lam Mộng Đạo Tôn sử dụng, nằm trong tổ hợp năm pháp bảo cùng phối hợp nhằm phá vỡ Phong Giới Đại Trận. Trong quá trình phá trận, dây đàn đụng độ trận linh của đại trận và bị cây roi tử ý ngưng tụ từ trận linh tấn công, hai bên va chạm kịch liệt. Sau đó, theo lệnh của Lam Mộng Đạo Tôn, dây đàn tự nổ tung, hy sinh bản thân để xé rộng khe hở trên trận pháp, tạo điều kiện phá trận.","congNang":["Phá trận — phối hợp cùng bốn pháp bảo khác đối kháng trận linh Phong Giới Đại Trận @c1424","Tự hủy nổ tung theo lệnh chủ nhân để xé rộng khe hở trên trận pháp @c1424"],"chuSoHuu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1424","denChuong":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1424","loai":"dung","importance":"major","giaiDoan":"Nổ tung phá Phong Giới Đại Trận","text":"Dây đàn bị cây roi tử ý từ trận linh tấn công, hai vật va chạm kịch liệt. Sau đó theo lệnh nổ tung để xé rộng khe hở trên Phong Giới Đại Trận.","anchor":"đánh thẳng tới dây đàn của Lam Mộng Đạo Tôn"}]},"nguon":["@c1424"],"uyLuc":"Nổ tung đủ sức xé rộng khe hở trên Phong Giới Đại Trận, và trước đó va chạm kịch liệt với cây roi tử ý ngưng tụ từ trận linh mà không bị phá hủy ngay lập tức."},{"id":"chin-canh-hoa-tien-phi","name":"Chín cánh hoa (của tiên phi)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Nữ tử ung dung cao quý"],"trangThai":"bi-huy (nổ tung phá trận)","blurb":"Pháp bảo hình chín cánh hoa của một trong hai tiên phi, được sử dụng phối hợp cùng các pháp bảo khác để phá Phong Giới Đại Trận. Trong quá trình phá trận, bị lưu tinh chùy chín đầu do trận linh ngưng tụ tấn công, sau đó nổ tung theo lệnh để xé rộng khe hở trận pháp.","detail":"Chín cánh hoa là một trong năm pháp bảo phối hợp phá Phong Giới Đại Trận, do một trong hai tiên phi điều khiển. Trong trận chiến, pháp bảo này bị lưu tinh chùy chín đầu — vốn do ánh sáng đỏ của trận linh ngưng tụ thành — lao vào tấn công. Sau đó, chín cánh hoa nổ tung theo lệnh, lợi dụng sức nổ để xé rộng khe hở trên trận pháp, tạo điều kiện phá trận.","congNang":["Phá trận — phối hợp đối kháng trận linh Phong Giới Đại Trận @c1424","Tự hủy nổ tung theo lệnh để xé rộng khe hở trận pháp @c1424"],"chuSoHuu":[{"ten":"Nữ tử ung dung cao quý","tuChuong":"@c1424","denChuong":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1424","loai":"dung","importance":"major","giaiDoan":"Nổ tung phá Phong Giới Đại Trận","text":"Bị lưu tinh chùy chín đầu tấn công, sau đó nổ tung theo lệnh xé rộng khe hở trận pháp.","anchor":"lao thẳng tới chín cánh hoa của tiên phi"}]},"nguon":["@c1424"],"uyLuc":"Nổ tung đủ sức xé rộng khe hở trên Phong Giới Đại Trận @c1424"},{"id":"con-mat-dong-tu-han-bang","name":"Con mắt đồng tử trong hàn băng","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Đồng tử tam đồng chi tu"],"trangThai":"bi-huy (nổ tung phá trận)","blurb":"Pháp bảo của đồng tử cực tây Thái Cổ Tinh Thần, là một trong năm pháp bảo phối hợp phá Phong Giới Đại Trận. Con mắt đồng tử được phong ấn trong hàn băng, khi kích hoạt có thể tự hủy nổ tung để xé rộng khe hở trận pháp.","detail":"Con mắt đồng tử trong hàn băng là một trong năm pháp bảo được sử dụng phối hợp nhằm phá vỡ Phong Giới Đại Trận. Trong quá trình phá trận, pháp bảo này bị chiến xa khổng lồ lớn hơn vạn trượng — vốn là trận linh của Phong Giới Đại Trận — bắn lửa tấn công. Sau đó, theo lệnh, con mắt đồng tử nổ tung nhằm xé rộng khe hở trên trận pháp, hoàn thành sứ mệnh phá trận của nó.","congNang":["Phá trận — phối hợp cùng bốn pháp bảo khác đối kháng trận linh Phong Giới Đại Trận","Tự hủy nổ tung theo lệnh để xé rộng khe hở trận pháp @c1424"],"chuSoHuu":[{"ten":"Đồng tử tam đồng chi tu","tuChuong":"@c1424","denChuong":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1424","loai":"dung","importance":"major","giaiDoan":"Nổ tung phá Phong Giới Đại Trận","text":"Bị chiến xa khổng lồ bắn lửa tấn công, sau đó nổ tung theo lệnh xé rộng khe hở trận pháp.","anchor":"Nó lao thẳng tới con mắt cho đồng tử trong hàn băng tạo thành"}]},"nguon":["@c1424"],"uyLuc":"Nổ tung xé rộng khe hở trên Phong Giới Đại Trận, đủ sức chống lại trận linh là chiến xa khổng lồ lớn hơn vạn trượng @c1424","dacDiem":"Hình dạng là con mắt đồng tử được phong ấn trong hàn băng; mang tính chất tiêu hao — tự hủy khi hoàn thành sứ mệnh phá trận"},{"id":"ba-quy-anh-tien-phi","name":"Ba quỷ ảnh (bổn mạng huyết tiên phi)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Nữ tử hồng y tóc đỏ"],"trangThai":"bi-huy (nổ tung phá trận)","blurb":"Ba quỷ ảnh là pháp bảo do ba giọt bổn mạng huyết của tiên phi hóa thành, được sử dụng trong trận chiến phá Phong Giới Đại Trận. Đây là một trong năm pháp bảo phối hợp phá trận, có thể tự hủy nổ tung để xé rộng khe hở trận pháp.","detail":"Ba quỷ ảnh được hình thành từ ba giọt bổn mạng huyết của tiên phi, là một trong năm pháp bảo phối hợp cùng nhau nhằm phá vỡ Phong Giới Đại Trận. Trong quá trình phá trận, ba quỷ ảnh bị Lang nha bổng — vốn dính máu đen do ánh sáng đen của trận linh ngưng tụ — tấn công. Sau đó, ba quỷ ảnh nổ tung theo lệnh, xé rộng khe hở trận pháp, hoàn thành vai trò phá trận bằng cách tự hủy.","congNang":["Phá trận — đối kháng trận linh Phong Giới Đại Trận, phối hợp cùng bốn pháp bảo khác","Tự hủy nổ tung theo lệnh để xé rộng khe hở trận pháp @c1424"],"chuSoHuu":[{"ten":"Nữ tử hồng y tóc đỏ","tuChuong":"@c1424","denChuong":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1424","loai":"dung","importance":"major","giaiDoan":"Nổ tung phá Phong Giới Đại Trận","text":"Ba quỷ ảnh bị Lang nha bổng dính máu đen tấn công, sau đó nổ tung theo lệnh xé rộng khe hở trận pháp.","anchor":"đánh thẳng tới ba quỷ ảnh do ba giọt bổn mạng huyết của tiên phi hóa thành"}]},"nguon":["@c1424"],"uyLuc":"Nổ tung theo lệnh, xé rộng khe hở của Phong Giới Đại Trận @c1424","dacDiem":"Do ba giọt bổn mạng huyết của tiên phi hóa thành; là pháp bảo dùng một lần, hoàn thành sứ mệnh bằng cách tự hủy"},{"id":"ngoc-boi-chu-nhan-phong-gioi","name":"Ngọc bội chủ nhân Phong Giới","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chủ nhân Phong Giới"],"trangThai":"dang-co","blurb":"Ngọc bội mang khí tức chủ nhân Phong Giới, tự xuất hiện trên Phong Giới Đại Trận. Có thể kích hoạt Khai Thiên Phủ từ xa chém giết tu sĩ giới ngoại và phát ra màn ánh sáng phong tỏa kẻ địch.","detail":"Ngọc bội tự hiện ra trên Phong Giới Đại Trận khi lỗ hổng mở, mang khí tức của chủ nhân Phong Giới — vị chủ nhân đã tự dung nhập vào trận pháp. Khi xuất hiện, ngọc bội kích hoạt Khai Thiên Phủ chém hai lần, giết gần mười nghìn tu sĩ giới ngoại, đồng thời phát ra màn ánh sáng nhẹ nhàng bao phủ phong tỏa kẻ địch. Ngọc bội đại diện cho ý chí và sức mạnh còn sót lại của chủ nhân Phong Giới, hoạt động như một cơ chế phòng ngự tự động của Phong Giới Đại Trận.","congNang":["Kích hoạt Khai Thiên Phủ từ xa, chém giết tu sĩ giới ngoại @c1425","Phát ra màn ánh sáng nhẹ nhàng phong tỏa kẻ địch @c1425"],"chuSoHuu":[{"ten":"Chủ nhân Phong Giới","tuChuong":"@c1425","denChuong":"","cachCoDuoc":"Vốn sở hữu, gắn liền trận pháp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1425","loai":"xuất hiện","importance":"major","giaiDoan":"Kích hoạt bảo vệ giới nội","text":"Xuất hiện trên Phong Giới Đại Trận, kích hoạt Khai Thiên Phủ chém hai lần giết gần mười nghìn tu sĩ giới ngoại, đồng thời phong tỏa lão già gầy nhom bằng màn sáng.","anchor":"ngọc bội trong trận pháp lại lóe lên hào quang, nhanh chóng hóa thành một màn ánh sáng nhẹ nhàng, bao phủ lão già này"}]},"nguon":["@c1425"],"uyLuc":"Kích hoạt Khai Thiên Phủ chém hai lần giết gần mười nghìn tu sĩ giới ngoại @c1425","dacDiem":"Mang khí tức chủ nhân Phong Giới, tự xuất hiện trên Phong Giới Đại Trận khi có ngoại xâm"},{"id":"toc-an-hoa-tuoc-toc","name":"Tộc ấn Hỏa Tước Tộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão tổ Hỏa Tước tộc"],"trangThai":"dang-co","blurb":"Tộc ấn của Hỏa Tước Tộc, có thể hóa thành hỏa điểu đen mang hư hỏa lực và khí tức cực nóng tấn công.","detail":"Lão tổ Hỏa Tước Tộc thi triển tộc ấn, hóa thành hỏa điểu màu đen mang theo hư hỏa lực và khí tức cực nóng, chứa hương hỏa vô tận của Hỏa Tước Tộc.","congNang":["Biến hóa thành hỏa điểu đen mang hư hỏa lực tấn công"],"chuSoHuu":[{"ten":"Lão tổ Hỏa Tước tộc","tuChuong":"@c1425","denChuong":"","cachCoDuoc":"Tộc bảo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1425","loai":"dùng","importance":"normal","giaiDoan":"Tấn công Vương Lâm trong đại chiến","text":"Lão tổ Hỏa Tước Tộc phóng tộc ấn hóa hỏa điểu đen mang hư hỏa lực tấn công Vương Lâm.","anchor":"tộc ấn của Hỏa Tước Tộc hiện lên, một hỏa điểu màu đen ầm ầm bay ra, mang theo một tia hư hỏa lực"}]},"nguon":["@c1425"]},{"id":"ho-ti-co-than","name":"Hộ tí Cổ Thần","cn":"护臂古神","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"hư tổn dần","blurb":"Hộ tí trên cánh tay phải Vương Lâm, khi kích hoạt triệu Cổ Thần khổng lồ hộ thể che chở chủ nhân và có thể phản kích. Mỗi lần sử dụng lại xuất hiện thêm vết nứt, pháp bảo đang hư hại dần theo thời gian.","detail":"Khi kích hoạt, Cổ Thần khổng lồ hiện ra ôm lấy Vương Lâm che chở toàn thân. Trong trận chiến tại hương hỏa giới của Nam Chiếu Thượng Nhân, Cổ Thần lấy lưng đỡ đòn bàn tay khổng lồ cấp Không Linh rồi xoay người tung quyền phản kích đánh văng đòn tấn công đó. Sau mỗi lần sử dụng, Cổ Thần tiêu tan hóa lại thành hộ tí nhưng trên bề mặt xuất hiện thêm vết nứt, cho thấy pháp bảo đang dần hư hại.","congNang":["Triệu Cổ Thần khổng lồ hộ thể, ôm lấy chủ nhân che chở toàn thân @c1426","Cổ Thần có thể phản kích, tung quyền đánh văng đòn tấn công cấp Không Linh @c1426"],"dacDiem":"Mỗi lần dùng thêm vết nứt, hư hại dần theo thời gian","uyLuc":"Đỡ được và phản kích đòn Không Linh sơ kỳ","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1426","denChuong":"","cachCoDuoc":"Chưa rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1426","loai":"dùng","importance":"major","giaiDoan":"Triệu Cổ Thần đỡ đòn Không Linh","text":"Vương Lâm triệu hộ tí Cổ Thần trong hương hỏa giới Nam Chiếu Thượng Nhân. Cổ Thần lấy lưng đỡ bàn tay khổng lồ Không Linh rồi tung quyền đánh văng bàn tay vạn trượng. Hộ tí tiêu tan hóa lại nhưng xuất hiện thêm vết nứt.","anchor":"chậm rãi tiêu tan, hóa thành một cái hộ tí, lại xuất hiện trên tay phải của Vương Lâm"}]},"capNhatToi":"@c1426","nguon":["@c1426"]},{"id":"hai-cot-su-ton-van-lac","name":"Hài cốt sư tôn Vân Lạc","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vân Lạc"],"trangThai":"hong","blurb":"Bộ hài cốt màu đen của sư tôn Vân Lạc đại ti, mang khí tức tang thương, là di vật và phương tiện cứu mạng cuối cùng của nàng. Khi đối diện Cực Cảnh của Vương Lâm, hài cốt được lấy ra chắn đòn, hấp thu tia chớp đỏ rồi sụp đổ, hóa cơn lốc cuốn hồn phách Vân Lạc biến mất trong thiên địa.","detail":"Hài cốt sư tôn của Vân Lạc đại ti là di vật còn sót lại từ vị sư tôn đã mất của nàng, toàn thân màu đen, toát ra khí tức tang thương. Trong trận chiến với Vương Lâm, khi bị Cực Cảnh truy sát, Vân Lạc lấy bộ hài cốt này ra làm lá chắn cuối cùng. Hài cốt hấp thu được tia chớp đỏ của Cực Cảnh rồi sụp đổ tan rã, nhưng ngay lúc vỡ, nó hóa thành một cơn lốc bảo vệ hồn phách chủ nhân, cuốn hồn phách Vân Lạc dung nhập vào trong và biến mất giữa thiên địa. Đây là phương tiện cứu mạng cuối cùng mà Vân Lạc sở hữu, thể hiện mối liên kết sâu sắc giữa sư đồ ngay cả sau khi vị sư tôn đã qua đời.","congNang":["Hấp thu công kích cường đại — hài cốt chịu được tia chớp đỏ từ Cực Cảnh của Vương Lâm trước khi sụp đổ @c1433","Khi vỡ tan hóa thành cơn lốc bảo vệ hồn phách chủ nhân, cuốn hồn phách Vân Lạc dung nhập và biến mất trong thiên địa @c1433"],"hinhDang":"Hài cốt màu đen, lộ khí tức tang thương","nguonGoc":"Di vật sư tôn của Vân Lạc đại ti","chuSoHuu":[{"ten":"Vân Lạc","tuChuong":"@c1433","denChuong":"","cachCoDuoc":"Di vật sư tôn truyền lại","trangThai":"đã dùng — vỡ"}],"capNhatToi":"@c1433","tabs":{"tienTrinh":[{"chuong":"@c1433","loai":"dùng","importance":"major","giaiDoan":"Bị dùng chắn Cực Cảnh rồi vỡ tan","text":"Vân Lạc lấy hài cốt sư tôn ra chắn Cực Cảnh của Vương Lâm. Hài cốt hấp thu tia chớp đỏ rồi sụp đổ, hóa cơn lốc cuốn hồn phách nàng biến mất.","anchor":"Một khối hài cốt màu đen đột nhiên xuất hiện trước mặt nàng"}]},"nguon":["@c1433"],"uyLuc":"Chịu được một kích của Cực Cảnh — pháp thuật cấp tối cao của Vương Lâm — trước khi sụp đổ, và khi vỡ vẫn đủ lực hóa lốc cuốn hồn phách chủ nhân thoát đi.","dacDiem":"Toàn thân màu đen, toát khí tức tang thương; là loại di vật chỉ dùng được một lần, tự hủy để cứu mạng chủ nhân."},{"id":"cay-cung-phong-du","name":"Cây cung của Phong Dư","cn":null,"aliases":["Cung Lý Quảng","Cây cung","Cung của Chưởng Tôn Phong Dư","Cung Lý tộc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Phong Dư","Chưởng Tôn","Thủ Đồ"],"trangThai":"lơ lửng trước lỗ hổng Phong Giới Đại Trận","blurb":"Cây cung do Phong Dư — ngón cái trong hàng thủ đồ của Chưởng Tôn — sử dụng nhắm bắn Vương Lâm qua lỗ hổng Phong Giới Đại Trận. Cung có khả năng ngưng tụ sức sống thành mũi tên hư ảo, uy lực đủ sức áp chế trận linh và suýt giết chết Vương Lâm.","detail":"Phong Dư (nam tử áo trắng, mang danh hiệu ngón cái trong hàng thủ đồ Chưởng Tôn) giương cây cung này nhắm vào mi tâm Vương Lâm ngay khi trận chiến sắp kết thúc, sát khí tập trung dữ dội. Cung bắn ra hai mũi tên hư ảo được ngưng tụ từ sức sống, áp chế trận linh của Phong Giới Đại Trận, suýt lấy mạng Vương Lâm. Vương Lâm nhận ra mình đã từng nhìn thấy cây cung này, ngụ ý hai người từng chạm mặt hoặc cung mang lai lịch đặc biệt. Sau khi bắn xong, Phong Dư ném cung ra.","nguon":["@c1435","@c1437"],"tabs":{"tienTrinh":[{"chuong":"@c1437","loai":"dùng","importance":"major","giaiDoan":"Thủ Đồ bắn hai mũi tên vào Vương Lâm","text":"Thủ Đồ bắn hai mũi tên hư ảo áp chế trận linh Phong Giới Đại Trận, suýt giết Vương Lâm. Sau đó ném cung ra trước lỗ hổng đại trận, đưa điều kiện ba cơ hội lấy cung.","anchor":"dường như có một ý niệm tồn tại từ vạn cổ điên cuồng từ trong cây cung theo một mũi tên này bộc phát ra"}]},"congNang":["Ngưng tụ sức sống thành mũi tên hư ảo để bắn ra @c1437","Áp chế trận linh của Phong Giới Đại Trận @c1437"],"chuSoHuu":[{"ten":"Lý Quảng","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"không rõ"},{"ten":"Chưởng Tôn","tuChuong":"","denChuong":"","cachCoDuoc":"Sở hữu hiện tại","trangThai":"đang sở hữu"},{"ten":"Thủ Đồ","tuChuong":"@c1437","denChuong":"@c1437","cachCoDuoc":"Được sư tôn giao mang tới","trangThai":"đã ném ra trước đại trận"}],"uyLuc":"Hai mũi tên hư ảo từ cung áp chế được trận linh Phong Giới Đại Trận, suýt giết chết Vương Lâm @c1437."},{"id":"mui-ten-ly-quang-goc","name":"Mũi tên Lý Quảng (gốc)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (bảo vật từ quê hương Đạo cổ)","soHuu":[],"trangThai":"mat-tich","blurb":"Mũi tên duy nhất của cung Lý Quảng, sau khi bắn rơi mắt trái Đạo cổ đã mang theo mắt trái phá tan hư không biến mất, tung tích bất minh.","detail":"Mũi tên gốc của cây cung Lý Quảng. Năm xưa bắn rơi mắt trái Đạo cổ rồi mang theo mắt trái phá tan hư không biến mất hoàn toàn. Vương Lâm suy luận: tìm được mũi tên sẽ tìm được mắt trái Đạo cổ, nếu ai tìm ra sẽ dấy lên tranh đoạt không thua gì Thiên Nghịch Châu. Thuộc bộ cung Lý Quảng.","nguonGoc":"Quê hương Đạo cổ, thuộc bộ cung Lý Quảng","dacDiem":"Biến mất sau khi bắn trúng mắt trái Đạo cổ, tung tích bất minh","boCha":"cay-cung-phong-du","congNang":["Bắn rơi mắt trái Đạo cổ, mang theo mắt trái phá tan hư không biến mất"],"tabs":{"tienTrinh":[{"chuong":"@c1436","loai":"nhắc tới","importance":"normal","giaiDoan":"Vương Lâm hồi tưởng","text":"Vương Lâm nhớ lại mũi tên duy nhất sau khi bắn rơi mắt trái Đạo cổ đã mang theo mắt trái phá tan hư không biến mất, suy luận tìm được mũi tên sẽ tìm được mắt trái.","anchor":"mũi tên kinh thiên kia hiện giờ có còn tồn tại hay không, và nó đang ở nơi nào"}]},"nguon":["@c1436"]},{"id":"mui-ten-hu-ao-nhu-bac","name":"Mũi tên hư ảo nhũ bạc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tạo vật tạm thời","soHuu":["Thủ Đồ"],"trangThai":"da-dung","blurb":"Mũi tên hư ảo nhũ bạc là đạn dược đặc biệt được hóa thành từ hơn nửa sức sống của Thủ Đồ khi buông dây cung Lý Quảng, mang tiếng gào thét kinh thiên có sức chấn thần cực mạnh. Mũi tên xuyên qua lỗ hổng Phong Giới Đại Trận, gây thương vong lớn cho tu sĩ cả hai phía giới nội lẫn giới ngoại.","detail":"Khi Thủ Đồ buông dây cung Lý Quảng, hơn nửa sức sống bị cung hấp thụ và hóa thành một mũi tên hư ảo màu trắng nhũ bạc. Mũi tên lao qua lỗ hổng trên Phong Giới Đại Trận, phát ra tiếng gào thét chấn động khiến vô số tu sĩ cả giới ngoại lẫn giới nội thất khiếu chảy máu, một số trọng thương chết tại chỗ. Mũi tên thuộc bộ cung Lý Quảng, không phải vật thể tồn tại sẵn mà được ngưng tụ tức thời từ sinh lực của người bắn, đánh đổi bằng cái giá hơn nửa sức sống.","boCha":"cay-cung-phong-du","congNang":["Phát ra tiếng gào thét chấn thần khiến tu sĩ thất khiếu chảy máu, trọng thương hoặc chết tại chỗ @c1436","Xuyên qua lỗ hổng Phong Giới Đại Trận, gây chấn động toàn bộ trận pháp @c1436"],"tabs":{"tienTrinh":[{"chuong":"@c1436","loai":"xuất hiện","importance":"major","giaiDoan":"Thủ Đồ bắn cung","text":"Thủ Đồ buông dây cung, hơn nửa sức sống hóa thành mũi tên hư ảo nhũ bạc lao qua lỗ hổng Phong Giới Đại Trận, gây chấn động kịch liệt toàn bộ trận pháp.","anchor":"hóa thành một mũi tên hư ảo màu trắng nhũ, theo dây cung bật lên, ầm ầm rời khỏi dây cung"}]},"nguon":["@c1436"],"uyLuc":"Tiếng gào thét của mũi tên khiến vô số tu sĩ cả giới ngoại lẫn giới nội thất khiếu chảy máu, một số trọng thương chết tại chỗ @c1436","dacDiem":"Mũi tên không phải vật thể sẵn có mà được hóa thành từ hơn nửa sức sống của người bắn khi buông dây cung Lý Quảng, mang hình dạng hư ảo màu trắng nhũ bạc"},{"id":"la-chan-vay-thai-a-la","name":"Lá chắn vảy Thái A La","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thái A La"],"trangThai":"đã vỡ","blurb":"Vảy đen nhạt toàn thân Thái A La tách ra hợp thành tấm lá chắn có ba vảy vàng quỷ dị ở giữa, cầm cự mũi tên cung Lý Quảng đúng ba nhịp thở rồi vỡ.","detail":"Năng lực thiên phú của mãnh thú Thái A La. Vảy đen nhạt trên toàn thân tách ra hợp thành tấm lá chắn, trung tâm có ba chiếc vảy màu vàng quỷ dị. Cầm cự được mũi tên từ cung cổ Lý Quảng đúng ba nhịp thở rồi vảy vỡ tan.","congNang":["Tạo khiên chắn từ vảy thân thể @c1437"],"tabs":{"tienTrinh":[{"chuong":"@c1437","loai":"dùng","importance":"normal","giaiDoan":"Thái A La dùng chắn mũi tên cho Vương Lâm","text":"Thái A La dùng lá chắn vảy cầm cự mũi tên thứ hai đúng ba nhịp thở, hai tay vỡ nát, vảy tan.","anchor":"Ở giữa tấm lá chắn này có ba chiếc vảy màu vàng rất quỷ dị"}]},"capNhatToi":"@c1437","nguon":["@c1437"]},{"id":"cay-cung-ly-toc","name":"Cây cung Lý tộc","cn":"","aliases":["Cung Lý Quảng","Cây cung","Cung của Chưởng Tôn Phong Dư","Cung Lý tộc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cực phẩm)","soHuu":["Lý tộc"],"trangThai":"dang tranh doat","blurb":"Cây cung của Lý tộc xuất hiện lơ lửng bên ngoài Phong Giới Đại Trận, bất động trước mọi lực tấn công dù cuồng phong, chín tu chân tinh bốc cháy hay giao chiến giữa Chưởng Tôn và Chiến lão quỷ diễn ra xung quanh. Chiến lão quỷ tuyên bố ngoài Lý tộc ra không ai có thể làm chủ cây cung này, rồi cất bước đi nhận.","detail":"Cây cung xuất hiện bên ngoài Phong Giới Đại Trận, trong bối cảnh toàn bộ cuồng phong liên thủ giới nội, chín tu chân tinh bốc cháy và cuộc giao chiến giữa Chưởng Tôn với Chiến lão quỷ đều diễn ra xung quanh nó. Dù chịu đủ mọi dạng lực tấn công, cây cung chỉ hơi vặn vẹo ánh sáng mà hoàn toàn không biến đổi hay dịch chuyển. Chiến lão quỷ khẳng định cung thuộc về Lý tộc, ngoài Lý tộc ra không ai có thể làm chủ, và cất bước tiến tới nhận lấy cây cung (@c1438).","congNang":["Bất động hoàn toàn trước mọi lực tấn công từ bên ngoài — cuồng phong, tu chân tinh lực, giao chiến cấp Chưởng Tôn đều không thể khiến cung biến đổi hay dịch chuyển (@c1438)"],"dacDiem":"Bất động trước mọi lực tấn công, chỉ hơi vặn vẹo ánh sáng mà không hề biến đổi; thuộc về Lý tộc, ngoài Lý tộc ra không ai có thể làm chủ.","hinhDang":"Cung","nguonGoc":"Lý tộc","chuHienThoi":"Đang tranh đoạt","tabs":{"tienTrinh":[{"chuong":"@c1438","loai":"xuất hiện","importance":"major","giaiDoan":"Bị tranh đoạt giữa giới nội và giới ngoại","text":"Cung lơ lửng bất động trước mọi tấn công, Chiến lão quỷ tuyên bố cung thuộc Lý tộc, cất bước đi nhận.","anchor":"Cây cung này ngoài Lý tộc ra thì không ai có thể làm chủ"}]},"nguon":["@c1438"]},{"id":"bon-menh-huyet-nguoi-dien","name":"Bổn mệnh huyết (của người điên)","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc thù","phamCap":"Cực phẩm","soHuu":["Người điên"],"trangThai":"da-dung","blurb":"Bổn mệnh huyết là ngụm máu bổn mệnh mà người điên cắn đầu lưỡi tự nguyện phun ra để cứu chữa Vương Lâm, trân quý hơn máu thường vô số lần. Khi nhập vào cơ thể, nó bộc phát uy áp khủng khiếp áp chế cả Cổ Thần lực lẫn Đạo Cổ lực, thúc đẩy quá trình thay tủy đổi mạch quy mô lớn.","detail":"Trong lúc cứu chữa Vương Lâm, người điên cắn đầu lưỡi phun ra ngụm bổn mệnh huyết lên cơ thể hắn (@c1442). Đây là loại máu trân quý hơn máu thường vô số lần, mang theo uy áp bản mệnh của người điên. Khi nhập vào cơ thể Vương Lâm, bổn mệnh huyết bộc phát uy áp khủng khiếp, đồng thời áp chế mọi lực lượng trong cơ thể bao gồm cả Cổ Thần lực và Đạo Cổ lực, từ đó thúc đẩy quá trình biến đổi tủy sống quy mô lớn. Điểm đặc biệt là máu bổn mệnh này chỉ phát huy tác dụng khi người điên tự nguyện phun ra; nếu bị ép rút thì hoàn toàn vô dụng.","congNang":["Uy áp áp chế mọi lực lượng trong cơ thể người nhận, bao gồm cả Cổ Thần lực và Đạo Cổ lực (@c1442)","Thúc đẩy quá trình thay tủy đổi mạch quy mô lớn (@c1442)","Chỉ có tác dụng khi người điên tự nguyện cắn lưỡi phun ra, bị ép rút thì vô dụng (@c1442)"],"chuSoHuu":[{"ten":"Người điên","tuChuong":"@c1442","denChuong":"","cachCoDuoc":"Bổn mệnh huyết của chính mình","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1442","loai":"dùng","importance":"major","giaiDoan":"Người điên phun bổn mệnh huyết lên Vương Lâm","text":"Người điên cắn đầu lưỡi phun bổn mệnh huyết — trân quý hơn máu thường vô số lần — lên cơ thể Vương Lâm, thúc đẩy biến đổi tủy sống toàn diện.","anchor":"Ngụm máu tươi này là bổn mệnh của hắn, so với máu tươi bình thường trân quý hơn gấp vô số lần"}]},"nguon":["@c1442"],"uyLuc":"Bộc phát uy áp khủng khiếp đủ sức áp chế cả Cổ Thần lực lẫn Đạo Cổ lực trong cơ thể người nhận.","dacDiem":"Trân quý hơn máu thường vô số lần, phải do người điên tự nguyện cắn đầu lưỡi phun ra mới có hiệu quả."},{"id":"sau-ma-tinh-co-ma","name":"Sáu ma tinh Cổ Ma","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Sáu ma tinh Cổ Ma là sáu tinh điểm ngưng tụ từ huyết nhục thi thể Cổ Ma, được Vương Lâm dung nhập vào mắt phải kết hợp với kim quang bảy tinh điểm Cổ Thần trên mi tâm. Thi thể Cổ Ma hoàn toàn biến mất sau quá trình ngưng tụ này.","detail":"Vương Lâm hóa giải huyết nhục thi thể Cổ Ma thành ma khí ngưng tụ vào sáu ma tinh, rồi đưa dung nhập vào mắt phải ấn lên tia chớp màu vàng, kết hợp với kim quang bảy tinh điểm Cổ Thần trên mi tâm. Quá trình này khiến thi thể Cổ Ma hoàn toàn tiêu biến, toàn bộ tinh hoa được chuyển hóa thành sáu tinh điểm dung hợp vào mắt phải của Vương Lâm.","congNang":["Cung cấp ma lực dung hợp vào mắt phải, kết hợp kim quang bảy tinh điểm Cổ Thần @c1445"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1445","denChuong":"","cachCoDuoc":"Ngưng tụ từ thi thể Cổ Ma","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1445","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ và dung nhập mắt phải","text":"Vương Lâm hóa giải huyết nhục Cổ Ma thành sáu ma tinh, đưa dung nhập vào mắt phải kết hợp kim quang bảy tinh điểm Cổ Thần. Thi thể Cổ Ma hoàn toàn tiêu hủy.","anchor":"sáu ma tinh dung nhập vào trong mắt của hắn, ấn lên trên tia chớp màu vàng kia"}]},"nguon":["@c1445"]}]};
